  // SERVER.JS - Complete Node.js server with browserless integration
  serverJs: `const express = require('express');
const cors = require('cors');
const path = require('path');
const { exec } = require('child_process');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(cors());
app.use(express.json());
app.use(express.static('public'));

// Serve main page
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// API endpoint to trigger browserless
app.post('/api/browserless', async (req, res) => {
  console.log('🌐 Triggering browserless...');
  
  exec('python ../claude_sdk_browser_runner.py create', (error, stdout, stderr) => {
    if (error) {
      console.error('Browserless error:', error.message);
      return res.status(500).json({ 
        success: false, 
        error: error.message 
      });
    }
    
    try {
      const result = JSON.parse(stdout);
      console.log('✅ Browserless result:', result);
      res.json(result);
    } catch (parseError) {
      res.json({ 
        success: true, 
        output: stdout,
        message: 'Browserless command executed'
      });
    }
  });
});

// API endpoint to navigate to this server
app.post('/api/navigate-here', async (req, res) => {
  console.log(\`🔗 Navigating browserless to localhost:\${PORT}\`);
  
  exec(\`python ../claude_sdk_browser_runner.py navigate --port \${PORT}\`, (error, stdout, stderr) => {
    if (error) {
      return res.status(500).json({ success: false, error: error.message });
    }
    
    try {
      const result = JSON.parse(stdout);
      res.json(result);
    } catch (parseError) {
      res.json({ success: true, output: stdout });
    }
  });
});

// Start server
app.listen(PORT, () => {
  console.log(\`🚀 Healthcare tool running on http://localhost:\${PORT}\`);
  console.log('📱 React/Node.js with browserless integration active');
  
  // Auto-trigger browserless after 3 seconds
  setTimeout(() => {
    console.log('🌐 Auto-starting browserless integration...');
    exec('python ../claude_sdk_browser_runner.py create', (error, stdout) => {
      if (!error) {
        console.log('✅ Browserless integration started successfully');
        
        // Auto-navigate to this server after 2 more seconds
        setTimeout(() => {
          exec(\`python ../claude_sdk_browser_runner.py navigate --port \${PORT}\`, () => {
            console.log('🔗 Browserless navigated to this healthcare tool');
          });
        }, 2000);
      } else {
        console.log('⚠️ Browserless not available (normal in some environments)');
      }
    });
  }, 3000);
});`,

